+// LLM provider interface.
+//
+// All feature modules route through `generate()` — never call providers directly.
+// Real provider implementations (local, byok-anthropic, byok-openai, byok-google)
+// land in later PRs. For PR 1, only the default "not configured" provider exists.
+//
+// See docs/UMBRELLA-PLAN.md ("LLM integration") for the full design.
+
+export type LLMCapability = 'text' | 'vision' | 'structured' | 'streaming';
+
+export interface GenerateOptions {
+  prompt: string;
+  schema?: unknown;
+  stream?: boolean;
+  capabilities?: LLMCapability[];
+}
+
+export interface LLMProvider {
+  id: string;
+  available: boolean;
+  generate(opts: GenerateOptions): Promise<string> | AsyncIterable<string>;
+}
+
+const NOT_CONFIGURED: LLMProvider = {
+  id: 'not-configured',
+  available: false,
+  async generate() {
+    throw new Error('LLM not configured');
+  },
+};
+
+let activeProvider: LLMProvider = NOT_CONFIGURED;
+
+export function generate(opts: GenerateOptions): Promise<string> | AsyncIterable<string> {
+  return activeProvider.generate(opts);
+}
+
+export interface LLMHandle {
+  generate: typeof generate;
+  available: boolean;
+  configure: (provider: LLMProvider) => void;
+}
+
+export function useLLM(): LLMHandle {
+  return {
+    generate,
+    available: activeProvider.available,
+    configure: (provider) => {
+      activeProvider = provider;
+    },
+  };
+}","path":"src/llm/index.ts","commit_id":"e18c15624141092695e18f7a70a9c516e10c0fd7","original_commit_id":"e18c15624141092695e18f7a70a9c516e10c0fd7","user":{"login":"gemini-code-assist[bot]","id":176961590,"node_id":"BOT_kgDOCow4Ng","avatar_url":"https://avatars.githubusercontent.com/in/956858?v=4","gravatar_id":"","url":"https://api.github.com/users/gemini-code-assist%5Bbot%5D","html_url":"https://github.com/apps/gemini-code-assist","followers_url":"https://api.github.com/users/gemini-code-assist%5Bbot%5D/followers","following_url":"https://api.github.com/users/gemini-code-assist%5Bbot%5D/following{/other_user}","gists_url":"https://api.github.com/users/gemini-code-assist%5Bbot%5D/gists{/gist_id}","starred_url":"https://api.github.com/users/gemini-code-assist%5Bbot%5D/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/gemini-code-assist%5Bbot%5D/subscriptions","organizations_url":"https://api.github.com/users/gemini-code-assist%5Bbot%5D/orgs","repos_url":"https://api.github.com/users/gemini-code-assist%5Bbot%5D/repos","events_url":"https://api.github.com/users/gemini-code-assist%5Bbot%5D/events{/privacy}","received_events_url":"https://api.github.com/users/gemini-code-assist%5Bbot%5D/received_events","type":"Bot","user_view_type":"public","site_admin":false},"body":"![medium](https://www.gstatic.com/codereviewagent/medium-priority.svg)

