+// LLM provider interface.
+//
+// All feature modules route through `generate()` — never call providers directly.
+// Real provider implementations (local, byok-anthropic, byok-openai, byok-google)
+// land in later PRs. For PR 1, only the default "not configured" provider exists.
+//
+// See docs/UMBRELLA-PLAN.md ("LLM integration") for the full design.
+
+export type LLMCapability = 'text' | 'vision' | 'structured' | 'streaming';
+
+export interface GenerateOptions {
+  prompt: string;
+  schema?: unknown;
+  stream?: boolean;
+  capabilities?: LLMCapability[];
+}
+
+export interface LLMProvider {
+  id: string;
+  available: boolean;
+  generate(opts: GenerateOptions): Promise<string> | AsyncIterable<string>;
+}
+
+const NOT_CONFIGURED: LLMProvider = {
+  id: 'not-configured',
+  available: false,
+  async generate() {
+    throw new Error('LLM not configured');
+  },
+};
+
+let activeProvider: LLMProvider = NOT_CONFIGURED;
+
+export function generate(opts: GenerateOptions): Promise<string> | AsyncIterable<string> {
+  return activeProvider.generate(opts);
+}
+
+export interface LLMHandle {
+  generate: typeof generate;
+  available: boolean;
+  configure: (provider: LLMProvider) => void;
+}
+
+export function useLLM(): LLMHandle {
+  return {
+    generate,
+    available: activeProvider.available,
+    configure: (provider) => {
+      activeProvider = provider;
+    },
+  };
+}","path":"src/llm/index.ts","commit_id":"e9f67c9f14faad6cf97e06832a682672aa885e3f","original_commit_id":"e18c15624141092695e18f7a70a9c516e10c0fd7","user":{"login":"patflynn","id":7862557,"node_id":"MDQ6VXNlcjc4NjI1NTc=","avatar_url":"https://avatars.githubusercontent.com/u/7862557?v=4","gravatar_id":"","url":"https://api.github.com/users/patflynn","html_url":"https://github.com/patflynn","followers_url":"https://api.github.com/users/patflynn/followers","following_url":"https://api.github.com/users/patflynn/following{/other_user}","gists_url":"https://api.github.com/users/patflynn/gists{/gist_id}","starred_url":"https://api.github.com/users/patflynn/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/patflynn/subscriptions","organizations_url":"https://api.github.com/users/patflynn/orgs","repos_url":"https://api.github.com/users/patflynn/repos","events_url":"https://api.github.com/users/patflynn/events{/privacy}","received_events_url":"https://api.github.com/users/patflynn/received_events","type":"User","user_view_type":"public","site_admin":false},"body":"`useLLM` now tracks the provider in `useState` and subscribes to a module-level subscriber set; `configure()` notifies subscribers so any component using the hook re-renders when the active provider changes.","created_at":"2026-05-17T19:51:16Z","updated_at":"2026-05-17T19:51:16Z","html_url":"https://github.com/gunk-dev/flux/pull/65#discussion_r3255383689","pull_request_url":"https://api.github.com/repos/gunk-dev/flux/pulls/65","_links":{"self":{"href":"https://api.github.com/repos/gunk-dev/flux/pulls/comments/3255383689"},"html":{"href":"https://github.com/gunk-dev/flux/pull/65#discussion_r3255383689"},"pull_request":{"href":"https://api.github.com/repos/gunk-dev/flux/pulls/65"}},"reactions":{"url":"https://api.github.com/repos/gunk-dev/flux/pulls/comments/3255383689/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"start_line":63,"ori